import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        if (n == 0) {
            return new long[0];
        }

        long[] distinctArr = Arrays.copyOf(nums, n);
        Arrays.sort(distinctArr);
        int uniqueCount = 1;
        for (int i = 1; i < n; i++) {
            if (distinctArr[i] != distinctArr[i - 1]) {
                distinctArr[uniqueCount++] = distinctArr[i];
            }
        }
        distinctArr = Arrays.copyOf(distinctArr, uniqueCount);

        Map<Long, Integer> compMap = new HashMap<>();
        for (int i = 0; i < uniqueCount; i++) {
            compMap.put(distinctArr[i], i);
        }

        int[] compNums = new int[n];
        for (int i = 0; i < n; i++) {
            compNums[i] = compMap.get(nums[i]);
        }

        int qCount = queries.length;
        long[] ans = new long[qCount];
        int blockSize = (int) Math.sqrt(n);

        if (qCount == 0) {
            return ans;
        }

        class Query {
            int l, r, threshold, idx;
            Query(int l, int r, int threshold, int idx) {
                this.l = l;
                this.r = r;
                this.threshold = threshold;
                this.idx = idx;
            }
        }
        Query[] qArr = new Query[qCount];
        for (int i = 0; i < qCount; i++) {
            long[] query = queries[i];
            int l = (int) query[0];
            int r = (int) query[1];
            int threshold = (int) query[2];
            qArr[i] = new Query(l, r, threshold, i);
        }

        Arrays.sort(qArr, (a, b) -> {
            int blockA = a.l / blockSize;
            int blockB = b.l / blockSize;
            if (blockA != blockB) {
                return Integer.compare(blockA, blockB);
            }
            if ((blockA & 1) == 0) {
                return Integer.compare(a.r, b.r);
            } else {
                return Integer.compare(b.r, a.r);
            }
        });

        int[] cnt = new int[uniqueCount];
        TreeSet<Integer>[] bucket = new TreeSet[n + 1];
        for (int i = 0; i <= n; i++) {
            bucket[i] = new TreeSet<>((a, b) -> {
                long valA = distinctArr[a];
                long valB = distinctArr[b];
                if (valA < valB) return -1;
                if (valA > valB) return 1;
                return 0;
            });
        }
        final int[] maxFreq = {0};

        java.util.function.Consumer<Integer> add = (index) -> {
            int x = compNums[index];
            int oldCnt = cnt[x];
            if (oldCnt > 0) {
                bucket[oldCnt].remove(x);
            }
            int newCnt = oldCnt + 1;
            cnt[x] = newCnt;
            bucket[newCnt].add(x);
            if (newCnt > maxFreq[0]) {
                maxFreq[0] = newCnt;
            }
        };

        java.util.function.Consumer<Integer> remove = (index) -> {
            int x = compNums[index];
            int oldCnt = cnt[x];
            bucket[oldCnt].remove(x);
            int newCnt = oldCnt - 1;
            cnt[x] = newCnt;
            if (newCnt > 0) {
                bucket[newCnt].add(x);
            }
            if (oldCnt == maxFreq[0] && bucket[oldCnt].isEmpty()) {
                maxFreq[0] = oldCnt - 1;
            }
        };

        int lPtr = 0, rPtr = -1;
        for (Query query : qArr) {
            int l = query.l;
            int r = query.r;
            while (rPtr < r) {
                rPtr++;
                add.accept(rPtr);
            }
            while (rPtr > r) {
                remove.accept(rPtr);
                rPtr--;
            }
            while (lPtr < l) {
                remove.accept(lPtr);
                lPtr++;
            }
            while (lPtr > l) {
                lPtr--;
                add.accept(lPtr);
            }

            if (maxFreq[0] < query.threshold) {
                ans[query.idx] = -1;
            } else {
                int compIdx = bucket[maxFreq[0]].first();
                ans[query.idx] = distinctArr[compIdx];
            }
        }

        return ans;
    }
}
